const states = msg.payload?.states || [];

if (!Array.isArray(states) || states.length === 0) {
    node.warn("No flight data received");
    return null;
}

const MIN_LAT = 36;
const MAX_LAT = 43;
const MIN_LON = -10;
const MAX_LON = -6;

msg.payload = states
  .filter(s => s[5] && s[6])
  .map(s => ({
    id: s[0],
    callsign: s[1]?.trim(),
    country: s[2],
    lon: s[5],
    lat: s[6],
    altitude: s[7],
    velocity: s[9],
    heading: s[10]
  }))
  .filter(f =>
    f.lat >= MIN_LAT && f.lat <= MAX_LAT &&
    f.lon >= MIN_LON && f.lon <= MAX_LON
  );

if (!Array.isArray(msg.payload) || msg.payload.length === 0) {
    node.warn("No flights over Portugal");
    return null;
}

return msg;

const f = msg.payload;
msg.flight = f;
msg.url = `https://api.open-meteo.com/v1/forecast?latitude=${f.lat}&longitude=${f.lon}&current_weather=true`;
return msg;

const w = msg.payload?.current_weather;
const f = msg.flight;

if (!w) {
    node.warn("No weather data");
    return null;
}

msg.payload = {
  ...f,
  weather: {
    temperature: w.temperature,
    windspeed: w.windspeed,
    winddirection: w.winddirection,
    weathercode: w.weathercode,
    time: w.time
  }
};

return msg;
